      { text: "Periodic fever, aphthous stomatitis, pharyngitis, adenitis (PFAPA) syndrome", type: "similar_wrong", distanceScore: 1, distanceLabel: "Close but wrong", explanation: "PFAPA occurs predominantly in young children with regular 3-5 week cycles featuring fever with aphthous ulcers, tonsillar exudates, and cervical lymphadenopathy; it lacks MEFV mutations and is not associated with peritonitis-like abdominal pain; MEFV genetic testing distinguishes FMF from PFAPA definitively." },
      { text: "Hyperimmunoglobulin D syndrome (HIDS)", type: "misconception", distanceScore: 2, distanceLabel: "Common misconception", explanation: "HIDS (mevalonate kinase deficiency from MVK mutation) causes recurrent fever attacks lasting 5-7 days with elevated IgD, cervical lymphadenopathy, and GI symptoms without the peritonitis-predominant pattern of FMF; HIDS predominantly affects Dutch and northern European populations, not Eastern Mediterranean ethnic groups." },
      { text: "Tumor necrosis factor receptor-associated periodic syndrome (TRAPS)", type: "wildly_wrong", distanceScore: 3, distanceLabel: "Way off", explanation: "TRAPS (autosomal dominant TNFRSF1A mutation) causes prolonged attacks lasting 1-3 weeks with migratory myalgia, periorbital edema, and distinctive skin manifestations; more common in northern European populations; confirmed MEFV autosomal recessive mutation definitively distinguishes FMF from TRAPS in this clinical scenario." }
