      { text: "AA amyloidosis with serum amyloid A protein depositing in glomeruli, causing nephrotic syndrome progressing to renal failure", type: "correct", distanceScore: 0, distanceLabel: "Correct", explanation: "Congo red staining with apple-green birefringence under polarized light is the histological hallmark of amyloid; in FMF, chronic elevation of serum amyloid A protein from recurrent inflammation leads to AA amyloid fibril formation; glomerular AA deposition causes the classic sequence of proteinuria, nephrotic syndrome, and progressive renal failure treatable only by controlling underlying FMF inflammation." },
      { text: "IgA nephropathy from recurrent inflammatory episodes", type: "similar_wrong", distanceScore: 1, distanceLabel: "Close but wrong", explanation: "IgA nephropathy presents with hematuria and mild proteinuria from mesangial IgA immune complex deposition detected by immunofluorescence, not Congo red staining; IgA nephropathy is not associated with FMF and would not show birefringence under polarized light; the Congo red finding definitively indicates amyloid deposition." },
      { text: "Lupus nephritis from FMF-associated autoimmunity", type: "misconception", distanceScore: 2, distanceLabel: "Common misconception", explanation: "FMF is an autoinflammatory disorder (innate immunity dysregulation) distinct from autoimmune conditions like SLE; lupus nephritis shows immune complex deposits and wire-loop lesions on electron microscopy with granular immunofluorescence; FMF does not cause anti-dsDNA antibodies or lupus nephritis; Congo red birefringence is specific for amyloid, not immune complex deposits." },
      { text: "AL amyloidosis from FMF-associated plasma cell dyscrasia", type: "wildly_wrong", distanceScore: 3, distanceLabel: "Way off", explanation: "AL amyloidosis results from immunoglobulin light chain deposition from plasma cell dyscrasias (multiple myeloma, MGUS); FMF specifically causes AA amyloidosis from serum amyloid A accumulation due to chronic inflammation; distinguishing AA from AL amyloidosis is critical because they have different treatments and immunohistochemical staining characteristics on biopsy." }
