      { text: "Pyloric or antral stenosis from post-ischemic scarring and fibrosis of the gastric outlet", type: "correct", distanceScore: 0, distanceLabel: "Correct", explanation: "Stage 1 GI mucosal ischemia and necrosis at the gastric antrum and pylorus (areas of maximum iron concentration) heals by fibrosis over 2-8 weeks post-ingestion; fibrous scar formation can cause progressive pyloric outlet obstruction presenting with non-bilious vomiting, early satiety, and weight loss; this late complication requires surgical management." },
      { text: "Chronic iron deficiency from ongoing GI blood loss", type: "similar_wrong", distanceScore: 1, distanceLabel: "Close but wrong", explanation: "The acute hemorrhagic gastroenteritis heals after the toxic episode; ongoing chronic blood loss is not the expected sequela; survivors of iron poisoning may actually have elevated iron stores from the original ingestion; the late structural complication is fibrous pyloric stenosis, not persistent mucosal hemorrhage." },
      { text: "Colonic strictures from iron crystallization in the colon", type: "misconception", distanceScore: 2, distanceLabel: "Common misconception", explanation: "Iron does not crystallize in the colon; colonic strictures are not a recognized late complication of iron ingestion; the gastric antrum and pylorus bear the maximum iron concentration from the ingested dose and undergo the most severe ischemic injury leading to fibrotic healing and outlet obstruction." },
      { text: "Barrett esophagus from acid injury worsened by iron", type: "wildly_wrong", distanceScore: 3, distanceLabel: "Way off", explanation: "Barrett esophagus results from chronic gastroesophageal acid reflux causing intestinal metaplasia; iron toxicity does not cause esophageal mucosal changes, increase acid reflux, or produce the chronic repetitive acid injury required for Barrett metaplasia; the esophagus is not a primary site of direct iron contact in ingestion toxicity." }
