      { text: "Carbonyl iron (slow-release) - same elemental content but slower absorption", type: "similar_wrong", distanceScore: 1, distanceLabel: "Close but wrong", explanation: "Carbonyl iron has 100% elemental iron by weight but dramatically slower absorption kinetics that significantly reduce peak serum iron levels; this slower release substantially limits free iron toxicity even with large ingestions; carbonyl iron carries materially lower acute toxicity risk per elemental milligram compared to rapidly absorbed ferrous sulfate." },
      { text: "Ferric polymaltose complex - equivalent toxicity to ferrous salts", type: "misconception", distanceScore: 2, distanceLabel: "Common misconception", explanation: "Ferric polymaltose complex (FPC) releases iron slowly from a stable complex and does not generate significant free ferrous iron; multiple case series demonstrate that FPC ingestions are substantially safer than ferrous salt ingestions even at similar milligram doses; equating FPC toxicity to ferrous sulfate overstates its danger." },
      { text: "Children's chewable iron supplements have the highest overdose risk due to sweet taste", type: "wildly_wrong", distanceScore: 3, distanceLabel: "Way off", explanation: "Children's chewable iron preparations typically contain 15-18mg elemental iron per tablet compared to 65mg in adult prenatal ferrous sulfate tablets; while palatability increases the likelihood of ingesting multiple tablets, the lower elemental dose per tablet makes adult prenatal supplements far more dangerous per unit ingested." }
