  {
    question: "B. pseudomallei is intrinsically resistant to which antibiotic class that would typically be used for gram-negative sepsis?",
    bloomLevel: "Recall",
    competencyCode: "MI4.3",
    competencyText: "Recall intrinsic resistance profile of Burkholderia pseudomallei",
    options: [
      { text: "Aminoglycosides and polymyxins (colistin) due to intrinsic resistance mechanisms", type: "correct", distanceScore: 0, distanceLabel: "Correct", explanation: "B. pseudomallei has intrinsic resistance to aminoglycosides (through active efflux pumps including BpeAB-OprB and ribosomal modification) and to polymyxins/colistin (through LPS modification with 4-amino-arabinose reducing polymyxin binding); this knowledge is critical when treating suspected melioidosis, as standard gram-negative sepsis regimens using these agents would fail." },
      { text: "Carbapenems - reserved for resistant gram-negatives but also ineffective here", type: "similar_wrong", distanceScore: 1, distanceLabel: "Close but wrong", explanation: "Carbapenems (meropenem, imipenem) are highly active against B. pseudomallei and are the preferred agents for severe neurological or septic shock melioidosis; meropenem is explicitly the alternative to ceftazidime for intensive phase treatment; claiming carbapenem ineffectiveness is factually incorrect and clinically dangerous." },
      { text: "Beta-lactam/beta-lactamase inhibitor combinations", type: "misconception", distanceScore: 2, distanceLabel: "Common misconception", explanation: "Piperacillin-tazobactam has some in vitro activity against B. pseudomallei but is not first-line; amoxicillin-clavulanate has been used in some oral step-down protocols; these combinations are not characterized by intrinsic resistance; the key clinical point is that aminoglycosides and polymyxins (commonly used for gram-negative sepsis) are ineffective." },
      { text: "Fluoroquinolones have no activity against B. pseudomallei", type: "wildly_wrong", distanceScore: 3, distanceLabel: "Way off", explanation: "Fluoroquinolones have documented in vitro activity against B. pseudomallei; ciprofloxacin and moxifloxacin have been evaluated; while not first-line due to inferior outcomes compared to ceftazidime and high relapse rates, they are not intrinsically resistant; the specific intrinsic resistances are to aminoglycosides and polymyxins, not to fluoroquinolones." }
    ],
    pubmedSource: { pmid: "33296681", title: "Systematic review and meta-analysis of diagnostic tests for diagnosis of melioidosis.", publicationType: "Systematic Review" }
  },
  {
    question: "An Australian Aboriginal child with malnutrition develops lung abscess and bacteremia. Melioidosis is confirmed. What additional diagnostic evaluation is essential given the risk of disseminated disease?",
    bloomLevel: "Application",
    competencyCode: "IM7.5",
    competencyText: "Apply comprehensive staging for disseminated melioidosis",
    options: [
      { text: "CT chest/abdomen (liver, spleen, kidney abscesses), echocardiography, and neuroimaging to identify all foci of dissemination", type: "correct", distanceScore: 0, distanceLabel: "Correct", explanation: "B. pseudomallei disseminates hematogenously to multiple organs; lung, liver, spleen, kidney, prostate, and brain are common abscess sites; identifying all foci is essential because undrained abscesses serve as protected intracellular sanctuaries requiring longer antibiotic treatment or drainage; echocardiography detects endocarditis which significantly changes management and treatment duration." },
      { text: "Chest X-ray and blood cultures are sufficient for staging", type: "similar_wrong", distanceScore: 1, distanceLabel: "Close but wrong", explanation: "Chest X-ray misses hepatic, splenic, renal, and cerebral abscesses that profoundly affect treatment decisions; blood cultures may be negative after empirical antibiotics are started; CT of chest and abdomen plus brain MRI are essential to identify the complete dissemination picture that determines treatment duration and need for drainage." },
      { text: "Bone marrow biopsy for B. pseudomallei", type: "misconception", distanceScore: 2, distanceLabel: "Common misconception", explanation: "Bone marrow involvement in melioidosis is rare; bone marrow biopsy is not a standard staging procedure; culture of multiple sites (blood, urine, throat, respiratory) and CT imaging to identify visceral and cerebral abscesses constitute the appropriate comprehensive staging approach." },
      { text: "Only bacteremia management is needed; abscess staging is not clinically important", type: "wildly_wrong", distanceScore: 3, distanceLabel: "Way off", explanation: "Undrained abscesses in melioidosis maintain bacteremia and prevent microbiological cure; visceral and cerebral abscesses may require CT-guided percutaneous drainage; their presence indicates longer antibiotic courses; failing to image for dissemination leads to treatment failure, relapse, and inadequate antibiotic duration decisions." }
    ],
    pubmedSource: { pmid: "33296681", title: "Systematic review and meta-analysis of diagnostic tests for diagnosis of melioidosis.", publicationType: "Systematic Review" }
  }
