  {
    question: "A patient from an endemic area for both visceral leishmaniasis and blastomycosis has fever, splenomegaly, and skin nodules. Which test specifically distinguishes between these two diagnoses?",
    bloomLevel: "Application",
    competencyCode: "MI4.4",
    competencyText: "Apply specific diagnostic testing to differentiate disseminated dimorphic fungal infection from visceral leishmaniasis",
    options: [
      { text: "Skin biopsy culture and histology - broad-based budding yeast confirms blastomycosis; Leishman-Donovan bodies in bone marrow biopsy confirm kala-azar", type: "correct", distanceScore: 0, distanceLabel: "Correct", explanation: "Tissue diagnosis is definitive: broad-based budding thick-walled yeast (8-15 microns) in skin biopsy confirms blastomycosis, while Giemsa-stained bone marrow showing intracellular amastigotes with kinetoplasts (Leishman-Donovan bodies) confirms kala-azar. Each diagnosis requires its own tissue specimen and staining approach." },
      { text: "Blood culture (both grow on standard media within 24 hours)", type: "similar_wrong", distanceScore: 1, distanceLabel: "Close but wrong", explanation: "Neither Leishmania nor Blastomyces grows on standard blood culture media within 24 hours. Blastomyces grows on fungal media at 25-30°C over days to weeks, and Leishmania requires specialized NNN media or promastigote culture. Blood cultures are neither the diagnostic method of choice nor rapid for either organism." },
      { text: "Serology alone is 100% sensitive and specific for both diseases", type: "misconception", distanceScore: 2, distanceLabel: "Common misconception", explanation: "Serology for both Leishmania and Blastomyces has significant limitations. Anti-Leishmania serology has variable sensitivity by region and cross-reacts with other diseases. Blastomyces antibody tests have poor sensitivity (~50%). Neither is 100% sensitive or specific; tissue diagnosis remains the gold standard." },
      { text: "PCR from blood differentiates all causes of fever and splenomegaly", type: "wildly_wrong", distanceScore: 3, distanceLabel: "Way off", explanation: "Blood PCR for Leishmania has reasonable sensitivity in endemic settings but is not widely available. No single blood PCR test reliably differentiates all causes of febrile splenomegaly. Tissue-based diagnosis (marrow biopsy for Leishmania; skin biopsy culture for Blastomyces) remains the most specific approach for both." }
    ],
    pubmedSource: { pmid: "27570207", title: "Canine visceral leishmaniasis in Iran: A systematic review and meta-analysis.", publicationType: "Systematic Review" }
  }
